@namespace Lumeo

<div class="@CssClass"
     style="@StyleString"
     data-direction="@DirectionAttr"
     data-vertical="@(Vertical ? "true" : "false")"
     data-pause-hover="@(PauseOnHover ? "true" : "false")"
     @attributes="AdditionalAttributes">
    <div class="lumeo-marquee-track">
        @ChildContent
    </div>
    <div class="lumeo-marquee-track" inert aria-hidden="true">
        @ChildContent
    </div>
</div>

@code {
    /// <summary>Content to scroll. Rendered twice (a live copy plus an
    /// <c>aria-hidden</c>/<c>inert</c> duplicate track) to create a seamless
    /// looping effect via CSS animation.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Scroll speed, mapped to an animation duration: Slow (60s), Normal
    /// (30s, default), or Fast (12s).</summary>
    [Parameter] public MarqueeSpeed Speed { get; set; } = MarqueeSpeed.Normal;

    /// <summary>Horizontal scroll direction (Left or Right). Inverted by <see cref="Reverse"/>.</summary>
    [Parameter] public MarqueeDirection Direction { get; set; } = MarqueeDirection.Left;

    /// <summary>Pauses the scroll animation while the pointer hovers the marquee.</summary>
    [Parameter] public bool PauseOnHover { get; set; }

    /// <summary>Flips <see cref="Direction"/> (Left becomes Right and vice versa).</summary>
    [Parameter] public bool Reverse { get; set; }

    /// <summary>Scrolls vertically instead of horizontally.</summary>
    [Parameter] public bool Vertical { get; set; }

    /// <summary>Additional CSS classes merged onto the outer wrapper.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures unmatched attributes and applies them to the outer wrapper.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => string.Join(" ", new[] { "lumeo-marquee", Class }.Where(s => !string.IsNullOrWhiteSpace(s)));

    private string DurationCss => Speed switch
    {
        MarqueeSpeed.Slow => "60s",
        MarqueeSpeed.Fast => "12s",
        _ => "30s"
    };

    private string StyleString => $"--lumeo-marquee-duration: {DurationCss};";

    // Reverse inverts the Direction parameter.
    private string DirectionAttr
    {
        get
        {
            var dir = Direction;
            if (Reverse) dir = dir == MarqueeDirection.Left ? MarqueeDirection.Right : MarqueeDirection.Left;
            return dir == MarqueeDirection.Right ? "right" : "left";
        }
    }

    public enum MarqueeSpeed { Slow, Normal, Fast }
    public enum MarqueeDirection { Left, Right }
}
